# Via atalho de teclado (durante sessão)
Shift+Tab  # ou Alt+M — alterna entre modos

# Via CLI ao iniciar
claude --permission-mode plan

# Via configuração persistente em settings.json
{
  "permissions": {
    "defaultMode": "acceptEdits"
  }
}

# Ativar/desativar durante sessão
Alt+T  # (Option+T no macOS)

# Via configuração
{
  "thinking": true
}
